INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('police-8b7f1efc-moex-00237', 'police-8b7f1efc', 'police-8b7f1efc-moex-113-9d260bf1', 'sub-police-8b7f1efc-03', NULL, 'single_choice', '依據「執行拘提逮捕解送使用戒具實施辦法」，下列敘述何者錯誤？', '["執行拘提、逮捕或解送時，對於被告或犯罪嫌疑人是甫生產後之婦女以及少年，一律不應使用 戒具", "警察人員於依法執行拘提、逮捕或解送職務時，得對被告或犯罪嫌疑人使用戒具", "使用戒具，以手銬為原則。但被告或犯罪嫌疑人有被劫持之虞情形時，得合併使用腳鐐、聯鎖 或束繩等", "使用戒具時，除應遵守比例原則，不得逾必要之程度外，另應注意避免公然暴露所使用之戒具"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:13+00:00", "source_pdf_sha1": "0feeda8c1bfd", "answer_pdf_sha1": "79a89b51fb96", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "501", "s": "0908", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察學與警察勤務", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00238', 'police-8b7f1efc', 'police-8b7f1efc-moex-113-9d260bf1', 'sub-police-8b7f1efc-03', NULL, 'single_choice', '依據內政部警政署所訂之「警察機關勤務督察實施規定」，下列敘述何者正確？', '["各級督察人員之督勤次數，每月每人不得少於4次，每次不得少於2小時", "勤務督導區分為駐區督導、隨機督導、專案督導及聯合督導等四類", "督導應掌握重點，但例假日、災變、勤務交接及用膳時間應減少督導，以免影響勤務運作", "依工作需要派遣配合實施之聯合督導，若非督察人員則除勤務督導外，以督導主管業務為原則"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:13+00:00", "source_pdf_sha1": "0feeda8c1bfd", "answer_pdf_sha1": "79a89b51fb96", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "501", "s": "0908", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察學與警察勤務", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00239', 'police-8b7f1efc', 'police-8b7f1efc-moex-113-9d260bf1', 'sub-police-8b7f1efc-03', NULL, 'single_choice', '「問題導向警政」（Problem-OrientedPolicing）是以「問題」解決為導向的警察勤務作為，下列 何者並非形成「問題」的要素？', '["事件反覆發生", "期待警方處理", "事件具獨特性", "事件具社區性"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:13+00:00", "source_pdf_sha1": "0feeda8c1bfd", "answer_pdf_sha1": "79a89b51fb96", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "501", "s": "0908", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察學與警察勤務", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00240', 'police-8b7f1efc', 'police-8b7f1efc-moex-113-9d260bf1', 'sub-police-8b7f1efc-03', NULL, 'single_choice', '下列有關警察勤務之敘述何者正確？', '["落實勤務執行，始能達成警察任務，而勤務規劃為主要推動力量", "督導人員督導發現重大優良事蹟，可當場頒發獎金即時獎勵", "各級督導人員除因勤務性質報准得著便服督勤外，應一律穿著制服", "警察局為勤務規劃監督機構，負責轄區警察勤務之規劃、指揮、管制、督導及考核，對重點性 勤務，需交由責任區警察分局執行，不可越俎代庖"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:13+00:00", "source_pdf_sha1": "0feeda8c1bfd", "answer_pdf_sha1": "79a89b51fb96", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "501", "s": "0908", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察學與警察勤務", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00241', 'police-8b7f1efc', 'police-8b7f1efc-moex-113-9d260bf1', 'sub-police-8b7f1efc-03', NULL, 'single_choice', '內政部為保障各警察機關實施輪班輪休服勤人員之健康權，特訂定「警察機關輪班輪休人員勤休 實施要點」，依據該要點規定，執行稽查、取締違反森林法或野生動物保育法勤務之警察人員服 勤時數為下列何者？', '["不得連續超過2日；每月超時服勤時數不得超過100小時", "不得連續超過3日；每月超時服勤時數不得超過100小時", "不得連續超過2日；每月超時服勤時數不得超過120小時", "不得連續超過3日；每月超時服勤時數不得超過80小時"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:13+00:00", "source_pdf_sha1": "0feeda8c1bfd", "answer_pdf_sha1": "79a89b51fb96", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "501", "s": "0908", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察學與警察勤務", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00242', 'police-8b7f1efc', 'police-8b7f1efc-moex-113-9d260bf1', 'sub-police-8b7f1efc-03', NULL, 'single_choice', '依據「警察機關輪班輪休人員勤休實施要點」，警察人員服勤時數以每日8小時為原則，但執行 下列何種勤務，超時服勤時間不受每日不得超過16小時限制？', '["刑事警察單位執行刑案偵查", "執行食安相關法令案件之勤務", "偵辦陳報內政部警政署列管之重大刑案或特殊刑案專案", "實際擔負內部管理及應變處置之主管勤務"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:13+00:00", "source_pdf_sha1": "0feeda8c1bfd", "answer_pdf_sha1": "79a89b51fb96", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "501", "s": "0908", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察學與警察勤務", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00243', 'police-8b7f1efc', 'police-8b7f1efc-moex-113-9d260bf1', 'sub-police-8b7f1efc-03', NULL, 'single_choice', '依據治安顧慮人口查訪辦法，有關治安顧慮人口之查訪，下列敘述何者正確？', '["警察發現治安顧慮查訪對象有違法之虞時，應以勸告或其他適當方法，促其不再犯", "曾犯森林法所定森林主副產物贓物罪者，屬治安顧慮人口查訪對象", "對於已在社會上享有一定程度聲望與地位之查訪對象，為避免影響查訪對象之名譽，應主動改 為夜間實施查訪", "曾犯槍砲彈藥刀械管制條例所定運輸槍砲彈藥刀械之罪者，屬治安顧慮人口查訪對象"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:13+00:00", "source_pdf_sha1": "0feeda8c1bfd", "answer_pdf_sha1": "79a89b51fb96", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "501", "s": "0908", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察學與警察勤務", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00244', 'police-8b7f1efc', 'police-8b7f1efc-moex-113-9d260bf1', 'sub-police-8b7f1efc-03', NULL, 'single_choice', '在警察勤務運作原理中，提出警察勤務應該主動先發式（proactive）的發現問題，而不是被動反 應式（reactive）的處理問題，前述是屬於下列何種勤務原理？', '["隨機原理", "散在原理", "機動原理", "活用原理"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:13+00:00", "source_pdf_sha1": "0feeda8c1bfd", "answer_pdf_sha1": "79a89b51fb96", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "501", "s": "0908", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察學與警察勤務", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00245', 'police-8b7f1efc', 'police-8b7f1efc-moex-113-9d260bf1', 'sub-police-8b7f1efc-03', NULL, 'single_choice', '依警察勤務區訪查作業規定第2點規定，下列何者並非記事人口？', '["依性侵害犯罪防治法第7條、第41條規定，應登記、報到之加害人", "依性侵害犯罪防治法第42條規定，應登記、報到之加害人", "依家庭暴力防治法第48條規定，應實施查訪之相對人（加害人）", "依跟蹤騷擾防制法第5 條規定，經警察機關書面告誡後二年內，再為跟蹤騷擾行為者"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:13+00:00", "source_pdf_sha1": "0feeda8c1bfd", "answer_pdf_sha1": "79a89b51fb96", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "501", "s": "0908", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察學與警察勤務", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00246', 'police-8b7f1efc', 'police-8b7f1efc-moex-113-9d260bf1', 'sub-police-8b7f1efc-03', NULL, 'single_choice', '下列何者警察機關係執行警察法第5條第1款拱衛中樞、準備應變及協助地方治安之保安警察業務？', '["內政部警政署保安警察第二總隊", "內政部警政署保安警察第三總隊", "內政部警政署保安警察第四總隊", "內政部警政署保安警察第七總隊"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:13+00:00", "source_pdf_sha1": "0feeda8c1bfd", "answer_pdf_sha1": "79a89b51fb96", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "501", "s": "0908", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察學與警察勤務", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL)
